/// </summary>
[ExtensionOf(formDataSourceStr(CustInvoiceJournal, CustInvoiceTrans))]
internal final class ETGCustInvoiceJournal_CustInvoiceTransDS_Extension
{
}

Method.Source:
/// <summary>
/// update design for custom fields
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    boolean isCylinderTrackingEnabled = SalesParameters::find().ETGEnableCylinderTracking;

    this.object(fieldNum(CustInvoiceTrans, ETGTermoValueUsageReal)).visible(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes);
    this.object(fieldNum(CustInvoiceTrans, ETGConnectionType)).visible(isCylinderTrackingEnabled);
    this.object(fieldNum(CustInvoiceTrans, ETGCylinderTrackPaymJourCreated)).visible(isCylinderTrackingEnabled);
    this.object(fieldNum(CustInvoiceTrans, ETGDepositAmount)).visible(isCylinderTrackingEnabled);
    this.object(fieldNum(CustInvoiceTrans, ETGDepositRate)).visible(isCylinderTrackingEnabled);
    this.object(fieldNum(CustInvoiceTrans, ETGFilledOrEmpty)).visible(isCylinderTrackingEnabled);

    return ret;
}
